import{_ as a,o as i,c as s,ae as t}from"./chunks/framework.DeBUZsJm.js";const u=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"clice/docs/en/guide/quick-start.md","filePath":"clice/docs/en/guide/quick-start.md"}'),o={name:"clice/docs/en/guide/quick-start.md"};function n(l,e,r,h,d,c){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><h2 id="editor-plugins" tabindex="-1">Editor Plugins <a class="header-anchor" href="#editor-plugins" aria-label="Permalink to &quot;Editor Plugins&quot;">​</a></h2><p>clice implements the <a href="https://microsoft.github.io/language-server-protocol" target="_blank" rel="noreferrer">Language Server Protocol</a>. Any editor that supports this protocol can theoretically work with clice to provide features like <code>code completion</code>, <code>diagnostics</code>, <code>go-to-definition</code>, and more.</p><p>However, beyond the standard protocol, clice also supports some protocol extensions. For better handling of these protocol extensions and better integration with editors, using clice plugins in specific editors is often a better choice. Most of them work out of the box and support clice&#39;s protocol extensions.</p><h3 id="visual-studio-code" tabindex="-1">Visual Studio Code <a class="header-anchor" href="#visual-studio-code" aria-label="Permalink to &quot;Visual Studio Code&quot;">​</a></h3><h3 id="vim-neovim" tabindex="-1">Vim/Neovim <a class="header-anchor" href="#vim-neovim" aria-label="Permalink to &quot;Vim/Neovim&quot;">​</a></h3><h3 id="others" tabindex="-1">Others <a class="header-anchor" href="#others" aria-label="Permalink to &quot;Others&quot;">​</a></h3><p>Other editors don&#39;t have available clice plugins yet (contributions welcome!). To use clice in them, please install clice yourself and refer to the specific editor&#39;s documentation on how to use a language server.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>If your editor plugin handles clice&#39;s download, you can skip this step.</p><h3 id="download-prebuilt-binary" tabindex="-1">Download Prebuilt Binary <a class="header-anchor" href="#download-prebuilt-binary" aria-label="Permalink to &quot;Download Prebuilt Binary&quot;">​</a></h3><p>Download clice binary version through the Release page.</p><h3 id="build-from-source" tabindex="-1">Build from Source <a class="header-anchor" href="#build-from-source" aria-label="Permalink to &quot;Build from Source&quot;">​</a></h3><p>Build clice from source yourself. For specific steps, refer to <a href="./../dev/build">build</a>.</p><h2 id="project-setup" tabindex="-1">Project Setup <a class="header-anchor" href="#project-setup" aria-label="Permalink to &quot;Project Setup&quot;">​</a></h2><p>For clice to correctly understand your code (e.g., find header file locations), you need to provide clice with a <code>compile_commands.json</code> file, also known as a <a href="https://clang.llvm.org/docs/JSONCompilationDatabase.html" target="_blank" rel="noreferrer">compilation database</a>. The compilation database provides compilation options for each source file.</p><h3 id="cmake" tabindex="-1">CMake <a class="header-anchor" href="#cmake" aria-label="Permalink to &quot;CMake&quot;">​</a></h3><p>For build systems using cmake, add the <code>-DCMAKE_EXPORT_COMPILE_COMMANDS=ON</code> option during build, for example:</p><div class="language-cmake vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmake</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cmake -B build -DCMAKE_EXPORT_COMPILE_COMMANDS=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span></span></code></pre></div><p>This will generate a <code>compile_commands.json</code> file in the <code>build</code> directory.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Note: This option only works when cmake&#39;s generator is set to makefile and ninja. For other generators, this option will be ignored, meaning the compilation database cannot be generated.</p></div><h3 id="bazel" tabindex="-1">Bazel <a class="header-anchor" href="#bazel" aria-label="Permalink to &quot;Bazel&quot;">​</a></h3><p>Bazel has no native support to generate a compilation database. The recommended solution is to use <a href="https://github.com/hedronvision/bazel-compile-commands-extractor" target="_blank" rel="noreferrer">bazel-compile-commands-extractor</a>. After setting it up, you can generate <code>compile_commands.json</code> with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bazel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @hedron_compile_commands//:refresh_all</span></span></code></pre></div><h3 id="visual-studio" tabindex="-1">Visual Studio <a class="header-anchor" href="#visual-studio" aria-label="Permalink to &quot;Visual Studio&quot;">​</a></h3><p>Visual Studio (2019 16.1+) can generate a compilation database via CMake integration. Open your project as a CMake project, then configure the generation in <code>CMakeSettings.json</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;configurations&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;x64-Debug&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;generator&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Ninja&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;buildRoot&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;\${projectDir}</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\\\</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;cmakeCommandArgs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-DCMAKE_EXPORT_COMPILE_COMMANDS=ON&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Alternatively, for MSBuild-based projects (<code>.vcxproj</code>), you can use <a href="https://github.com/pjbroad/compiledb-vs" target="_blank" rel="noreferrer">compiledb-vs</a> or <a href="https://github.com/clice-io/catter" target="_blank" rel="noreferrer">catter</a> to generate the compilation database.</p><h3 id="makefile" tabindex="-1">Makefile <a class="header-anchor" href="#makefile" aria-label="Permalink to &quot;Makefile&quot;">​</a></h3><p>For Makefile-based projects, use <a href="https://github.com/rizsotto/Bear" target="_blank" rel="noreferrer">bear</a> to intercept compilation commands:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bear</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span></span></code></pre></div><p>This will generate a <code>compile_commands.json</code> in the current directory. Note that <code>bear</code> requires a clean build to capture all commands — run <code>make clean</code> before <code>bear -- make</code> if needed.</p><p>Alternatively, if you use GNU Make, you can use <a href="https://github.com/nicktimko/compiledb" target="_blank" rel="noreferrer">compiledb</a>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">compiledb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span></span></code></pre></div><h3 id="meson" tabindex="-1">Meson <a class="header-anchor" href="#meson" aria-label="Permalink to &quot;Meson&quot;">​</a></h3><p>Meson generates a compilation database automatically during setup:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">meson</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>The <code>compile_commands.json</code> will be in the <code>build</code> directory.</p><h3 id="xmake" tabindex="-1">Xmake <a class="header-anchor" href="#xmake" aria-label="Permalink to &quot;Xmake&quot;">​</a></h3><p>Use one of the following approaches to generate a compilation database.</p><h4 id="command-line" tabindex="-1">Command Line <a class="header-anchor" href="#command-line" aria-label="Permalink to &quot;Command Line&quot;">​</a></h4><p>Run the following command to manually generate a compilation database:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> project</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile_commands</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --lsp=clangd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><blockquote><p>Compilation database generated manually doesn&#39;t automatically update itself. Re-generate if changes are made to the project.</p></blockquote><h4 id="vscode-extension" tabindex="-1">VSCode Extension <a class="header-anchor" href="#vscode-extension" aria-label="Permalink to &quot;VSCode Extension&quot;">​</a></h4><p>The Xmake official VSCode extension automatically generates the compilation database when <code>xmake.lua</code> is updated. However, it generates the database to the <code>.vscode</code> directory by default. Add this setting in <code>settings.json</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xmake.compileCommandsDirectory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;build&quot;</span></span></code></pre></div><p>to explicitly ask the extension to generate the compilation database in <code>build</code>.</p><h3 id="others-1" tabindex="-1">Others <a class="header-anchor" href="#others-1" aria-label="Permalink to &quot;Others&quot;">​</a></h3><p>For any other build system, you can use <a href="https://github.com/clice-io/catter" target="_blank" rel="noreferrer">catter</a> to generate a compilation database. It captures compilation commands through a fake compiler approach and is designed to work reliably with any build system that invokes a compiler executable.</p>`,50)])])}const k=a(o,[["render",n]]);export{u as __pageData,k as default};
